// Engine de decisão do bot
// Recebe: estado atual (Redis) + input do cliente
// Retorna: { mensagem, novo_estado, pausar_bot, ttl_estado }

const contact = $('Quando chamado pelo receiver').item.json;
const contactNumber = contact.contact_number;
const contentRaw = (contact.content || '').toString();
const instance = contact.instance || 'powerup-main';

// Normaliza entrada pra detectar dígito isolado
// Aceita: "1", " 1 ", "1.", "1)", etc.
const normalized = contentRaw.trim().replace(/[.)\s]/g, '');
const isDigit = /^[0-3]$/.test(normalized);
const digit = isDigit ? normalized : null;

// Lê estado do Redis (vem no campo propertyName quando existe)
const redisResult = $json.propertyName;
let currentStep = null;
if (redisResult && redisResult !== null && redisResult !== '') {
  try {
    const parsed = typeof redisResult === 'string' ? JSON.parse(redisResult) : redisResult;
    currentStep = parsed.step || null;
  } catch (e) {
    currentStep = null;
  }
}

// Mensagens do fluxo
const MSG_MENU = `👋 Olá! Você entrou em contato com a *PowerUP Informática*.\n\nEstamos prontos para te atender. Escolha uma das opções:\n\n*1* - Suporte Técnico\n*2* - Financeiro\n*3* - Vendas\n*0* - Atendimento humano\n\nDigite o número correspondente para continuar.`;

const MSG_INVALIDO = `Hmm, recebi sua mensagem 👍\nPra te direcionar melhor, digite só o número da opção:\n\n*1* - Suporte Técnico\n*2* - Financeiro\n*3* - Vendas\n*0* - Falar com atendente`;

const MSG_TECNICO_PEDIR = `🔧 Conectando ao suporte técnico.\n\nDescreva o problema que um técnico vai te atender em instantes.`;
const MSG_FINANCEIRO_PEDIR = `💰 Para questões financeiras, envie seu *CPF ou CNPJ*.`;
const MSG_VENDAS_PEDIR = `🛒 Nossa equipe comercial já está te atendendo.\n\nQual produto te interessa?`;
const MSG_HUMANO_PEDIR = `👤 Descreva o problema pra adiantar o chamado.`;

const MSG_TECNICO_FINAL = `✅ Passando para o Técnico, aguarde.`;
const MSG_FINANCEIRO_FINAL = `✅ Aguarde o setor financeiro.`;
const MSG_VENDAS_FINAL = `✅ Passando para o setor de vendas, aguarde.`;
const MSG_HUMANO_FINAL = `✅ Passando para um atendente humano. Aguarde!!`;

let response = {};

if (currentStep === null) {
  // Sem estado ativo → envia menu
  response = {
    mensagem: MSG_MENU,
    novo_estado: { step: 'menu', set_at: new Date().toISOString() },
    pausar_bot: false,
    ttl_estado: 3600
  };
} else if (currentStep === 'menu') {
  if (digit === '1') {
    response = {
      mensagem: MSG_TECNICO_PEDIR,
      novo_estado: { step: 'aguardando_problema_tecnico', set_at: new Date().toISOString() },
      pausar_bot: false,
      ttl_estado: 3600
    };
  } else if (digit === '2') {
    response = {
      mensagem: MSG_FINANCEIRO_PEDIR,
      novo_estado: { step: 'aguardando_doc', set_at: new Date().toISOString() },
      pausar_bot: false,
      ttl_estado: 3600
    };
  } else if (digit === '3') {
    response = {
      mensagem: MSG_VENDAS_PEDIR,
      novo_estado: { step: 'aguardando_produto', set_at: new Date().toISOString() },
      pausar_bot: false,
      ttl_estado: 3600
    };
  } else if (digit === '0') {
    response = {
      mensagem: MSG_HUMANO_PEDIR,
      novo_estado: { step: 'aguardando_problema_humano', set_at: new Date().toISOString() },
      pausar_bot: false,
      ttl_estado: 3600
    };
  } else {
    response = {
      mensagem: MSG_INVALIDO,
      novo_estado: { step: 'menu', set_at: new Date().toISOString() },
      pausar_bot: false,
      ttl_estado: 3600
    };
  }
} else if (currentStep === 'aguardando_problema_tecnico') {
  response = {
    mensagem: MSG_TECNICO_FINAL,
    novo_estado: null,
    pausar_bot: true,
    ttl_estado: 0
  };
} else if (currentStep === 'aguardando_doc') {
  response = {
    mensagem: MSG_FINANCEIRO_FINAL,
    novo_estado: null,
    pausar_bot: true,
    ttl_estado: 0
  };
} else if (currentStep === 'aguardando_produto') {
  response = {
    mensagem: MSG_VENDAS_FINAL,
    novo_estado: null,
    pausar_bot: true,
    ttl_estado: 0
  };
} else if (currentStep === 'aguardando_problema_humano') {
  response = {
    mensagem: MSG_HUMANO_FINAL,
    novo_estado: null,
    pausar_bot: true,
    ttl_estado: 0
  };
} else {
  // Estado desconhecido, reseta
  response = {
    mensagem: MSG_MENU,
    novo_estado: { step: 'menu', set_at: new Date().toISOString() },
    pausar_bot: false,
    ttl_estado: 3600
  };
}

return [{
  json: {
    contact_number: contactNumber,
    instance: instance,
    mensagem: response.mensagem,
    novo_estado: response.novo_estado,
    novo_estado_json: response.novo_estado ? JSON.stringify(response.novo_estado) : null,
    pausar_bot: response.pausar_bot,
    ttl_estado: response.ttl_estado,
    step_anterior: currentStep || 'null'
  }
}];
